effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

float mapChannel(float p, float f) {
    float t = mod(p+10.,1.);
    return clamp(abs(t-0.5)*4. - f, 0., 1.);
}

//float mapChannelSmooth(float p, float f) {
//    float t = mod(p+10.,1.);
//    return (smoothstep(f*2.0,0.,t) + smoothstep(f,1.,t) - f)*2.;
//    //return smoothstep(0.5,0.,t) + smoothstep(0.5,1.,t);
//}

void main() {

    mat3 rgb2yuv = mat3(
         0.299,     0.587,    0.114,
        -0.14713,  -0.28886,  0.436,
         0.615,    -0.51499, -0.10001
    );

    mat3 yuv2rgb = mat3(
        1.0,  0.0,      1.13983,
        1.0, -0.39465, -0.58060,
        1.0,  2.03211,  0.0
    );


    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    float luminance = dot(texColor.rgb, luminanceWeighting);
    float bscale = scaleBrightness ? luminance : 1.0;

    if(reverse) {
        luminance = 1.0 - luminance;
    }

    luminance = (luminance * repeat) + phase;

    //vec4 aa;
    //vec4 bb;
    //vec4 cc;
    //
    //float f = mix(0.333, 0.1, squeeze );
    //
    //if(smooth) {
    //    aa = mapChannelSmooth(luminance,f)*redColor;
    //    bb = mapChannelSmooth(luminance-1./3.0,f)*greenColor;
    //    cc = mapChannelSmooth(luminance-2./3.0,f)*blueColor;
    //} else {
    //    aa = mapChannel(luminance,f)*redColor;
    //    bb = mapChannel(luminance-1./3.0,f)*greenColor;
    //    cc = mapChannel(luminance-2./3.0,f)*blueColor;
    //}

    float f = mix(0.333, 0.1, squeeze );

    vec4 aa = mapChannel(luminance,f)*redColor;
    vec4 bb = mapChannel(luminance-1./3.0,f)*greenColor;
    vec4 cc = mapChannel(luminance-2./3.0,f)*blueColor;

    vec4 result = (aa+bb+cc);

    vec3 yuv = result.rgb * rgb2yuv;
    yuv.yz = yuv.yz * (saturation+1.0);
    result.rgb = yuv * yuv2rgb;

    gl_FragColor = mix( texColor, result*vec4(bscale,bscale,bscale,1.)*texColor.a, alpha);
}
